using System;

namespace MyLibrary
{
    class Foo
    {
        public event EventHandler ThresholdReached;

        protected virtual void OnThresholdReached(EventArgs e)
        {
            ThresholdReached?.Invoke(this, e); // Compliant - passing this as sender
        }
    }
}
